import React from "react";
import ReactDOM from "react-dom/client";
import App from "./App";
import HistoryPage from "./pages/HistoryPage";
import "./index.css";

const root = ReactDOM.createRoot(document.getElementById("root"));

function Router() {
  const [route, setRoute] = React.useState(window.location.pathname === "/history" ? "history" : "main");
  React.useEffect(() => {
    window.onpopstate = () => {
      setRoute(window.location.pathname === "/history" ? "history" : "main");
    };
  }, []);
  React.useEffect(() => {
    window.setAppRoute = setRoute;
  }, []);
  if (route === "history") return <HistoryPage />;
  return <App />;
}

root.render(
  <React.StrictMode>
    <Router />
  </React.StrictMode>
);
